import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom'; // Importez `Routes` et `Route`
import ProtectedRoute from './components/ProtectedRoute'; // Assurez-vous du bon chemin
import HomePage from './pages/HomePage'; // Votre page publique
import ProfilePage from './pages/ProfilePage'; // Votre page protégée
import LoginPage from './pages/LoginPage'; // Page de connexion
import AuthProvider from './context/AuthContext'; // Votre AuthProvider

const App = () => {
  return (
    <AuthProvider>
      <Router>
        <Routes> {/* Utilisez Routes au lieu de Switch */}
          <Route path="/login" element={<LoginPage />} /> {/* Remplacez component par element */}
          <Route path="/home" element={<HomePage />} />
          <ProtectedRoute path="/profile" element={<ProfilePage />} /> {/* Page protégée */}
          {/* Vous pouvez ajouter d'autres routes protégées ici */}
        </Routes>
      </Router>
    </AuthProvider>
  );
};

export default App;
